#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y)
{
    /* Parallelise the outer loop. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i)
    {
        const double* a_row = A[i].data();
        const double* b_row = B[i].data();
        double sum_t = 0.0;
        double sum_y = 0.0;

        for (int j = 0; j < n; ++j)
        {
            double xv = x[j];
            sum_t += a_row[j] * xv;
            sum_y += b_row[j] * xv;
        }

        tmp[i] = sum_t;
        y[i]  = alpha * sum_t + beta * sum_y;
    }
}
