/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
		      int n,
		      std::vector<double>& A,
		      std::vector<double>& B) {
    double *a = A.data();
    double *b = B.data();

    // Prevent OpenMP from creating overhead when n-2 == 0
    if (n <= 2) return;

    // Parallelize the two inner loops separately
    for (int t = 0; t < tsteps; ++t) {
        // First relaxation step: update B from A
        #pragma omp parallel for schedule(static) if(n>1024) \
            ivdep
        for (int i = 1; i < n - 1; ++i) {
            b[i] = 0.33333 * (a[i-1] + a[i] + a[i+1]);
        }

        // Second relaxation step: update A from B
        #pragma omp parallel for schedule(static) if(n>1024) \
            ivdep
        for (int i = 1; i < n - 1; ++i) {
            a[i] = 0.33333 * (b[i-1] + b[i] + b[i+1]);
        }
    }
}
