void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {
    // Form B := alpha * Aᵀ * B
    // A is MxM, B is MxN
    // Main loop parallelised over rows of B (outermost i).
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        // For each column j of B
        for (int j = 0; j < n; ++j) {
            // Accumulate products with rows k > i
            double sum = B[i][j];
            for (int k = i + 1; k < m; ++k) {
                sum += A[k][i] * B[k][j];
            }
            B[i][j] = alpha * sum;
        }
    }
}
