void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A) {

    // Use OpenMP to parallelise over outer dimension
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // local pointers for speed
        double *C_i   = C[i].data();
        const double *A_i = A[i].data();

        /* 1. Scale lower‑triangle of C by beta */
        for (int j = 0; j <= i; ++j)
            C_i[j] *= beta;

        /* 2. Accumulate alpha*A[i][k]*A[j][k] for each k */
        for (int k = 0; k < m; ++k) {
            double aik = A_i[k];
            for (int j = 0; j <= i; ++j) {
                C_i[j] += alpha * aik * A[j][k];
            }
        }
    }
}
