#include <vector>
#include <algorithm>
#include <cstdint>
#include <omp.h>

/* Floyd‑Warshall with double‐level blocking and OpenMP parallelisation.
 * The parallelisation shreds the outermost `k` loop, whereas inner loops
 * use cached references for cache friendly access. The code keeps the
 * exact semantics of the original (no change to function signature
 * nor to the behaviour of the algorithm). */
void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    const int blockSize = 64;                 // cache friendly block size
    const int nBlocks = (n + blockSize - 1) / blockSize;

    /* Parallelise over the outer `k` loop; each thread works on one
     * or more `k` values in a static schedule to give better load balance. */
    #pragma omp parallel for schedule(static)
    for (int kk = 0; kk < n; ++kk) {
        const int k = kk;
        const int* rowK = path[k].data();    // cached row reference

        /* Block the inner `i` loop to maximise data reuse of `rowK`. */
        for (int ii = 0; ii < n; ii += blockSize) {
            const int i = ii;
            int* rowI = path[i].data();

            /* Fallback to a simple loop when cache size is small. */
            for (int j = 0; j < n; ++j) {
                const int newVal = rowI[k] + rowK[j];
                if (newVal < rowI[j]) rowI[j] = newVal;
            }
        }
    }
}
