void kernel_seidel_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A) {
    // Cached row pointers for the entire array for fast access
    std::vector<double*> rows(n);
    for (int i = 0; i < n; ++i) rows[i] = A[i].data();

    const int stride = 3;            // number of terms in the stencil
    const double inv9 = 1.0 / 9.0;   // pre‑computed reciprocal

    for (int t = 0; t < tsteps; ++t) {
        // Parallel over the interior rows first to keep data locality
        #pragma omp parallel for schedule(static) collapse(2)
        for (int i = 1; i <= n - 2; ++i) {
            double* cur      = rows[i];
            double* prevRow  = rows[i - 1];
            double* nextRow  = rows[i + 1];
            for (int j = 1; j <= n - 2; ++j) {
                // compute the 3x3 stencil sum
                double sum =
                      prevRow[j - 1] + prevRow[j] + prevRow[j + 1]
                    + cur[j - 1] + cur[j] + cur[j + 1]
                    + nextRow[j - 1] + nextRow[j] + nextRow[j + 1];
                cur[j] = sum * inv9;
            }
        }
    }
