/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_2mm(int ni, int nj, int nk, int nl,
		double alpha,
		double beta,
		std::vector<std::vector<double>>& tmp,
		std::vector<std::vector<double>>& A,
		std::vector<std::vector<double>>& B,
		std::vector<std::vector<double>>& C,
		std::vector<std::vector<double>>& D)
{
    /* ------------------------------------------------------------------
       Step 1: compute tmp = alpha * A * B
       ------------------------------------------------------------------ */
    for (int i = 0; i < ni; ++i) {
        double* tmpRow = tmp[i].data();
        const double* aRow  = A[i].data();
        // set to zero
        std::fill(tmpRow, tmpRow + nj, 0.0);

        for (int k = 0; k < nk; ++k) {
            double aik = alpha * aRow[k];
            const double* bRow = B[k].data();
            for (int j = 0; j < nj; ++j) {
                tmpRow[j] += aik * bRow[j];
            }
        }
    }

    /* ------------------------------------------------------------------
       Step 2: compute D = beta*D + tmp * C
       ------------------------------------------------------------------ */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < ni; ++i) {
        for (int j = 0; j < nl; ++j) {
            double sum = beta * D[i][j];
            const double* tmpRow = tmp[i].data();
            for (int k = 0; k < nj; ++k) {
                sum += tmpRow[k] * C[k][j];
            }
            D[i][j] = sum;
        }
    }
}
