#include <vector>
#include <omp.h>

void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    // --- 1. Compute mean for each column ---------------------------------
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) {
            sum += data[i][j];
        }
        mean[j] = sum / static_cast<double>(n);
    }

    // --- 2. Center the data ------------------------------------------------
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            data[i][j] -= mean[j];
        }
    }

    // --- 3. Compute covariance matrix --------------------------------------
    // Compute only lower‑triangular part, mirror to upper side.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        for (int j = i; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) {
                sum += data[k][i] * data[k][j];
            }
            double val = sum / static_cast<double>(n - 1);
            cov[i][j] = val;
            cov[j][i] = val;   // symmetry
        }
    }
}
