/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_doitgen(int nr, int nq, int np,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<double>>& C4,
                    std::vector<double>& sum) {
    // Ensure sum has the correct size once (avoids re‑allocation in inner loops)
    sum.resize(np);

    // Parallelize the outer two loops.  The innermost loop is already
    // a small matrix‑vector product, which is highly cache friendly.
    #pragma omp parallel for collapse(2) schedule(static)
    for (int r = 0; r < nr; ++r) {
        for (int q = 0; q < nq; ++q) {

            // Each thread keeps its own temporary accumulator to avoid
            // false sharing on the `sum` vector.  The final result is written
            // back into the original `sum`.
            double localSum[128];          // 128 = max expected np
            constexpr int MAX_NP = 128;
            int sz = np;
            if (sz > MAX_NP) std::memcpy(localSum, sum.data(), sizeof(double) * sz);
            for (int p = 0; p < sz; ++p) localSum[p] = 0.0;

            for (int p = 0; p < sz; ++p) {
                double acc = 0.0;
                for (int s = 0; s < sz; ++s) {
                    acc += A[r][q][s] * C4[s][p];
                }
                localSum[p] = acc;
            }

            // Write the result back to A and to the shared sum vector
            for (int p = 0; p < sz; ++p) {
                A[r][q][p] = localSum[p];
                sum[p] = localSum[p];
            }
        }
    }
}
