#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_symm(int m, int n,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
    // Parallelise over the outermost loop; a static schedule gives almost
    // perfect load balance for the regular access pattern.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i)
    {
        double* Ci  = C[i].data();
        const double* Bi = B[i].data();
        const double* Ai = A[i].data();

        for (int j = 0; j < n; ++j)
        {
            double temp2 = 0.0;
            double B_ij = Bi[j];
            double A_ii = Ai[i];

            // accumulate the contribution from the strictly lower part
            for (int k = 0; k < i; ++k)
            {
                double B_kj = B[k][j];
                double A_ik = Ai[k];          // A[i][k]
                Ci[j]      += alpha * B_ij * A_ik;
                temp2      += B_kj     * A_ik;
            }

            // upper‑triangular contribution
            Ci[j] = beta * Ci[j] + alpha * B_ij * A_ii + alpha * temp2;
        }
    }
}
