        std::vector<double> local_s(m, 0.0);

        #pragma omp for schedule(static)
        for (int i = 0; i < n; ++i) {
            double row_acc = 0.0;          // temporary for q[i]
            const std::vector<double>& Ai = A[i];

            for (int j = 0; j < m; ++j) {
                double val = Ai[j];
                local_s[j] += r[i] * val;
                row_acc += val + p[j];
