/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trisolv(int n,
		    std::vector<std::vector<double>>& L,
		    std::vector<double>& x,
		    std::vector<double>& b)
{
    for (int i = 0; i < n; ++i) {
        double acc = b[i];

        // Vectorized inner loop: subtract L[i][j] * x[j] for j < i
        const std::vector<double> &row = L[i];
        int j = 0;

        // SSE intrinsics (8 doubles = 64 bytes) enable by compiler anyway.
        // We unroll by 4 for higher portability.
#pragma clang diagnostic push
#pragma clang diagnostic ignored "-Wpedantic"
        for (; j <= i - 4; j += 4) {
            acc -= row[j]   * x[j];
            acc -= row[j+1] * x[j+1];
            acc -= row[j+2] * x[j+2];
            acc -= row[j+3] * x[j+3];
        }
        for (; j < i; ++j) {
            acc -= row[j] * x[j];
        }
#pragma clang diagnostic pop

        x[i] = acc / row[i];
    }
}
