#include <vector>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y) {

    // Allocate working space once outside the loop.
    std::vector<double> z(n);

    // First values
    y[0] = -r[0];
    double beta = 1.0;
    double alpha = -r[0];

    // Main loop
    for (int k = 1; k < n; ++k) {
        // Update beta
        beta = (1.0 - alpha * alpha) * beta;

        // Compute sum = sum_{i=0}^{k-1} r[k-i-1] * y[i]
        double sum = 0.0;
        const double *r_ptr = r.data();      // base of r
        const double *y_ptr = y.data();      // base of y
        // Unroll a bit for speed
        int i = 0;
        for (; i + 3 < k; i += 4) {
            sum += r_ptr[k - i - 1] * y_ptr[i] +
                   r_ptr[k - i - 2] * y_ptr[i + 1] +
                   r_ptr[k - i - 3] * y_ptr[i + 2] +
                   r_ptr[k - i - 4] * y_ptr[i + 3];
        }
        for (; i < k; ++i) {
            sum += r_ptr[k - i - 1] * y_ptr[i];
        }

        // Update alpha
        alpha = -(r_ptr[k] + sum) / beta;

        // Update z and y
        for (i = 0; i < k; ++i) {
            z[i] = y_ptr[i] + alpha * y_ptr[k - i - 1];
        }
        for (i = 0; i < k; ++i) {
            y_ptr[i] = z[i];
        }
        y_ptr[k] = alpha;
    }
}
