extern "C" void kernel_nussinov(int n,
                                 std::vector<int>& seq,
                                 std::vector<std::vector<int>>& table) {
    // Ensure table is an `n x n` contiguous allocation
    // (the harness guarantees this, but we keep the accessor minimal).
    // Work on a raw pointer for speed.
    int* t = &table.front()[0];

    /* The algorithm uses 2‑D indices i,j.  We linearise them using
       row‑major order:  table[i][j] -> *(t + i*n + j).  */
    const int nn = n * n;

    // Process the DP in increasing diagonal order.
    // For each difference d = j - i, i runs from n-1 down to 0.
    #pragma omp parallel for schedule(static)
    for (int d = 1; d < n; ++d) {              // d = 1 … n-1
        for (int i = n - 1 - d; i >= 0; --i) { // i = n-1-d … 0
            int j = i + d;                    // j = i + d
            int idx = i * n + j;              // linear index

            int best = t[idx];                // current value

            // table[i][j-1]
            if (j - 1 >= 0)
                best = std::max(best, t[i * n + (j - 1)]);

            // table[i+1][j]
            if (i + 1 < n)
                best = std::max(best, t[(i + 1) * n + j]);

            // table[i+1][j-1] + match
            if (j - 1 >= 0 && i + 1 < n) {
                int temp = t[(i + 1) * n + (j - 1)];
                if (i < j - 1)
                    temp += match(seq[i], seq[j]);
                best = std::max(best, temp);
            }

            // k-splitting
            for (int k = i + 1; k < j; ++k) {
                int val = t[i * n + k] + t[(k + 1) * n + j];
                if (val > best) best = val;
            }

            t[idx] = best;
        }
    }
}
