        double ui1 = u1[i];
        double ui2 = u2[i];
        double* Ai = A[i].data();          // raw pointer to row i
        for (int j = 0; j < n; ++j) {
            Ai[j] += ui1 * v1[j] + ui2 * v2[j];
        }
    }

    // 2) Update x using y and transpose of A
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        for (int j = 0; j < n; ++j) {
            sum += beta * A[j][i] * y[j];
        }
        x[i] += sum;
    }

    // 3) Add z to x
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        x[i] += z[i];
    }

    // 4) Update w using x and A
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i) {
        double wi = 0.0;
        const double* Ai = A[i].data();
        for (int j = 0; j < n; ++j) {
            wi += alpha * Ai[j] * x[j];
        }
