/*----------------------------------------------------------
 * Optimized GEMM kernel
 *   C := alpha * A * B + beta * C
 *
 * Input:
 *   ni, nj, nk  - dimensions
 *   alpha, beta - scalars
 *   A (ni x nk), B (nk x nj), C (ni x nj)
 *----------------------------------------------------------*/
void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C)
{
    // Work with contiguous 1‑D arrays for linear access
    std::vector<double> a(ni * nk);
    std::vector<double> b(nk * nj);
    std::vector<double> c(ni * nj);

    // Flatten input matrices
    for (int i = 0; i < ni; ++i)
        std::copy(A[i].begin(), A[i].end(), a.begin() + i * nk);
    for (int i = 0; i < nk; ++i)
        std::copy(B[i].begin(), B[i].end(), b.begin() + i * nj);

    const std::size_t BLOCK = 64;   // cache‑friendly block size

    #pragma omp parallel
    {
        // Each thread gets its own temporary buffer for the current row of C
        std::vector<double> row_block(BLOCK);

        #pragma omp for schedule(static)
        for (int ii = 0; ii < ni; ++ii) {
            /* -------- scale C by beta -------- */
            double* ci = c.data() + ii * nj;
            for (int jj = 0; jj < nj; jj += 8) {          // AVX2 FMA
                __m256d vec = _mm256_loadu_pd(&ci[jj]);
                vec = _mm256_mul_pd(vec, _mm256_set1_pd(beta));
                _mm256_storeu_pd(&ci[jj], vec);
            }

            /* -------- accumulate alpha*A*B -------- */
            for (int kk = 0; kk < nk; ++kk) {
                double aik = a[ii * nk + kk];
                if (aik == 0.0) continue;    // skip zero factors

                const double* bj = b.data() + kk * nj;

                for (int jj = 0; jj < nj; jj += 8) {
                    __m256d vecA = _mm256_set1_pd(aik);
                    __m256d vecB = _mm256_loadu_pd(&bj[jj]);
                    __m256d vecC = _mm256_loadu_pd(&ci[jj]);
                    vecC = _mm256_fmadd_pd(vecA, vecB, vecC);
                    _mm256_storeu_pd(&ci[jj], vecC);
                }
            }
        }
    }

    // Copy result back into the output 2‑D vector
    for (int i = 0; i < ni; ++i)
        std::copy(c.begin() + i * nj, c.begin() + (i + 1) * nj, C[i].begin());
}
