void kernel_cholesky(int n,
		     std::vector<std::vector<double>>& A) {
    // Parallelise the inner loop over j; each i is independent.
    for (int i = 0; i < n; ++i) {
        // Pre‑fetch the current row pointer
        double* row_i = A[i].data();

        // Process lower triangular elements
        #pragma omp parallel for schedule(static)
        for (int j = 0; j < i; ++j) {
            double sum = 0.0;
            double* row_j = A[j].data();

            // Compute the dot product A[i][k] * A[j][k] for k < j
            for (int k = 0; k < j; ++k)
                sum += row_i[k] * row_j[k];

            row_i[j] = (row_i[j] - sum) / row_j[j];
        }

        // Diagonal element: subtract squared values
        double diag = row_i[i];
        for (int k = 0; k < i; ++k)
            diag -= row_i[k] * row_i[k];

        row_i[i] = std::sqrt(diag);
    }
