void kernel_lu(int n, std::vector<std::vector<double>>& A) {
    /* ----  Flatten the 2‑D structure into a contiguous 1‑D array  ---- */
    std::vector<double> flat(n * n);
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            flat[i * n + j] = A[i][j];

    /* ----  Perform the LU factorisation (Doolittle)  ---- */
    for (int i = 0; i < n; ++i) {
        /* ---  First pass: loop over columns < i  --- */
        for (int j = 0; j < i; ++j) {
            double sum = flat[i * n + j];
#pragma omp parallel for reduction(-:sum)
            for (int k = 0; k < j; ++k)
                sum -= flat[i * n + k] * flat[k * n + j];
            flat[i * n + j] = sum / flat[j * n + j];
        }

        /* ---  Second pass: columns >= i  --- */
        for (int j = i; j < n; ++j) {
            double sum = flat[i * n + j];
#pragma omp parallel for reduction(-:sum)
            for (int k = 0; k < i; ++k)
                sum -= flat[i * n + k] * flat[k * n + j];
            flat[i * n + j] = sum;
        }
    }

    /* ----  Copy the result back into the original 2‑D vector  ---- */
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            A[i][j] = flat[i * n + j];
