/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* QR Decomposition with Modified Gram Schmidt:
   http://www.inf.ethz.ch/personal/gander/ */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q) {
    /* Sequential outer loop over columns – each iteration is independent
       except for the data it writes into A, R and Q.  We keep it
       sequential to preserve numerical stability. */
    for (int k = 0; k < n; ++k) {
        /* Vector that will hold column k of Q for the current iteration */
        std::vector<double> qcol(m);

        /* Compute norm of column k of A (stored in qcol). */
        double norm2 = 0.0;
#pragma omp parallel for reduction(+:norm2) schedule(static)
        for (int i = 0; i < m; ++i) {
            double val = A[i][k];
            qcol[i] = val;           // cache for later reuse
            norm2 += val * val;
        }
        double rkk = std::sqrt(norm2);
        R[k][k] = rkk;

        /* Normalize column k to obtain Q(:,k) */
#pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i) {
            Q[i][k] = qcol[i] / rkk;
        }

        /* Process remaining columns j > k */
#pragma omp parallel for schedule(static)
        for (int j = k + 1; j < n; ++j) {
            double rkj = 0.0;
            /* Compute projection coefficient rkj = Q(:,k)' * A(:,j) */
            for (int i = 0; i < m; ++i) {
                rkj += Q[i][k] * A[i][j];
            }
            R[k][j] = rkj;

            /* Subtract projection from A(:,j) */
            for (int i = 0; i < m; ++i) {
                A[i][j] -= Q[i][k] * rkj;
            }
        }
    }
}
