    std::size_t rows, cols;
    double *ptr;                     // pointer to the first element

    Matrix(std::vector<std::vector<double>> &v, std::size_t r, std::size_t c)
        : data(v), rows(r), cols(c), ptr(&v[0][0]) {}
    inline double *row(std::size_t i) noexcept { return ptr + i * cols; }
    inline const double *row(std::size_t i) const noexcept { return ptr + i * cols; }
};

void kernel_3mm(int ni, int nj, int nk, int nl, int nm,
                std::vector<std::vector<double>>& E,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& F,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D,
                std::vector<std::vector<double>>& G)
{
    /* Wrap the input matrices in lightweight views that expose a
       contiguous representation.  No additional memory is allocated. */
    const Matrix a(A, ni, nk);
    const Matrix b(B, nk, nj);
    Matrix      e(E, ni, nj);
    const Matrix c(C, nj, nm);
    const Matrix d(D, nm, nl);
    Matrix      f(F, nj, nl);
    Matrix      g(G, ni, nl);

    /* 1) E = A * B   (ni × nj)  */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double *erow = e.row(i);
        const double *arer = a.row(i);
        for (int j = 0; j < nj; ++j) {
            double acc = 0.0;
            const double *bcol = &b.ptr[j];          // column j of B
            for (int k = 0; k < nk; ++k) {
                acc += arer[k] * bcol[k * nj];
            }
            erow[j] = acc;
        }
    }

    /* 2) F = C * D   (nj × nl)  */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < nj; ++i) {
        double *frow = f.row(i);
        const double *cer = c.row(i);
        for (int j = 0; j < nl; ++j) {
            double acc = 0.0;
            const double *dcol = &d.ptr[j];          // column j of D
            for (int k = 0; k < nm; ++k) {
                acc += cer[k] * dcol[k * nl];
            }
            frow[j] = acc;
        }
    }

    /* 3) G = E * F   (ni × nl)  */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double *grow = g.row(i);
        const double *erow = e.row(i);
        for (int j = 0; j < nl; ++j) {
            double acc = 0.0;
            const double *fcol = &f.ptr[j];          // column j of F
            for (int k = 0; k < nj; ++k) {
                acc += erow[k] * fcol[k * nl];
            }
            grow[j] = acc;
        }
    }
}
