inline void kernel_fdtd_2d(int tmax,
                           int nx,
                           int ny,
                           std::vector<std::vector<double>>& ex,
                           std::vector<std::vector<double>>& ey,
                           std::vector<std::vector<double>>& hz,
                           std::vector<double>& _fict_) {
    const double c1 = 0.5;
    const double c2 = 0.7;
    const int nym1 = ny - 1;
    const int nxm1 = nx - 1;
#pragma omp parallel
    {
        for (int t = 0; t < tmax; ++t) {
            /* ---- update ey[:,0] from source ----------
             *  This is serial but inexpensive; keep it outside OpenMP
             *  to avoid thread contention on the shared vector.
             */
            double* tmp_ptr = &ey[0][0];
            for (int j = 0; j < ny; ++j) {
                tmp_ptr[j] = _fict_[t];
            }

            /* ---- update ey[1..nx-1][0..ny-1] ----------
             */
#pragma omp for schedule(static)
            for (int i = 1; i < nx; ++i) {
