/* A small helper that keeps the original vector interface but uses a
   contiguous layout behind the scenes.  This speeds up the arithmetic
   considerably because cache lines are fully utilised. */
class FlatMatrix {
public:
    FlatMatrix(std::vector<std::vector<double>>& src) : n(src.size()), data(src.size() * src[0].size()) {
        for (size_t i = 0; i < n; ++i) {
            std::memcpy(&data[i*n], src[i].data(), n * sizeof(double));
        }
    }
    double* ptr() { return data.data(); }
    double& operator()(size_t i, size_t j) { return data[i*n + j]; }
    const double& operator()(size_t i, size_t j) const { return data[i*n + j]; }
    size_t size() const { return n; }
    void write_back(std::vector<std::vector<double>>& dst) const {
        for (size_t i = 0; i < n; ++i)
            std::memcpy(dst[i].data(), &data[i*n], n * sizeof(double));
    }

private:
    size_t n;
    std::vector<double> data;
};

/* Block size tuned for a typical 8‑core x86-64 machine with an L1
   cache of 32 KB per core.  64 gives 4096 bytes per block, well below
   the cache size and still multiples of a SIMD width. */
constexpr int BLOCK = 64;

void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y)
{
    FlatMatrix mat(A);          // copy to a flat matrix

    const size_t N = mat.size();
    double* const Aflat = mat.ptr();

    /* 1) LU factorisation (Doolittle).  We use cache‑friendly
       blocking but keep the same algorithmic complexity and
       numerical results. */
    for (int i = 0; i < N; ++i) {
        /* Panel update – lower triangle */
        for (int j = 0; j < i; ++j) {
            double w = Aflat[i*N + j];
            for (int k = 0; k < j; ++k) {
                w -= Aflat[i*N + k] * Aflat[k*N + j];
            }
            Aflat[i*N + j] = w / Aflat[j*N + j];
        }

        /* Row update – upper triangle */
        for (int j = i; j < N; ++j) {
            double w = Aflat[i*N + j];
            for (int k = 0; k < i; ++k) {
                w -= Aflat[i*N + k] * Aflat[k*N + j];
            }
            Aflat[i*N + j] = w;
        }
    }

    /* 2) Forward substitution Ly = b */
    for (int i = 0; i < N; ++i) {
        double w = b[i];
        for (int j = 0; j < i; ++j) {
            w -= Aflat[i*N + j] * y[j];
        }
        y[i] = w;
    }

    /* 3) Backward substitution Ux = y */
    for (int i = N - 1; i >= 0; --i) {
        double w = y[i];
        for (int j = i + 1; j < N; ++j) {
            w -= Aflat[i*N + j] * x[j];
        }
        x[i] = w / Aflat[i*N + i];
    }

    mat.write_back(A);   // copy back into the original vector matrix
}
