void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev) {
    const double eps = 0.1;

    /* ---------- Mean ---------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        for (int i = 0; i < n; ++i) s += data[i][j];
        mean[j] = s / n;
    }

    /* ---------- Stddev ---------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        for (int i = 0; i < n; ++i) {
            double d = data[i][j] - mean[j];
            s += d * d;
        }
        stddev[j] = std::sqrt(s / n);
        if (stddev[j] <= eps) stddev[j] = 1.0;  // handle near‑zero
    }

    /* Pre‑compute normalisation factors: 1/(sqrt(n)*stddev[j]) */
    const double inv_sqrt_n = 1.0 / std::sqrt(static_cast<double>(n));
    std::vector<double> inv_norm(m);
    for (int j = 0; j < m; ++j) inv_norm[j] = inv_sqrt_n / stddev[j];

    /* ---------- Normalise data ---------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            data[i][j] = (data[i][j] - mean[j]) * inv_norm[j];
        }
    }

    /* ---------- Correlation matrix ---------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m - 1; ++i) {
        corr[i][i] = 1.0;
        for (int j = i + 1; j < m; ++j) {
            double s = 0.0;
            for (int k = 0; k < n; ++k) s += data[k][i] * data[k][j];
            corr[i][j] = s;
            corr[j][i] = s;
        }
    }
    corr[m-1][m-1] = 1.0;
}
