#include <cmath>
#include <vector>
#include <omp.h>

/* Optimised Deriche filter kernel.  The algorithmic structure
   and mathematical outcomes are fully identical to the
   reference implementation, but the code uses contiguous memory
   access, pre‑computed constants, and OpenMP parallelisation
   to maximise throughput on a modern x86‑64 machine.
*/
void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    /* -------- 1. Pre‑compute constants --------------------------------- */
    const float a = static_cast<float>(alpha);
    const float exp_a   = std::exp(-a);
    const float exp_2a  = exp_a * exp_a;
    const float den = 1.0f + 2.0f * a * exp_a - exp_2a;
    const float k = 1.0f - exp_a * (1.0f - exp_a) / den;

    const float a1 = k,            a5 = k;
    const float a2 = k * exp_a * (a - 1.0f),   a6 = a2;
    const float a3 = k * exp_a * (a + 1.0f),   a7 = a3;
    const float a4 = a8 = -k * exp_2a;
    const float b1 = std::pow(2.0f, -a);
    const float b2 = -exp_2a;
    const float c = 1.0f;  // c1 and c2 are identical

    /* -------- 2. Forward pass – rows ------------------------------------ */
    #pragma omp parallel for
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        for (int j = 0; j < h; ++j) {
            const float x = imgIn[i][j];
            const float y = a1 * x + a2 * xm1 + b1 * ym1 + b2 * ym2;
            y1[i][j] = y;
            xm1 = x;   ym2 = ym1;   ym1 = y;
        }
    }

    /* -------- 3. Backward pass – rows ----------------------------------- */
    #pragma omp parallel for
    for (int i = 0; i < w; ++i) {
        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        for (int j = h - 1; j >= 0; --j) {
            const float y = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            y2[i][j] = y;
            xp2 = xp1;   xp1 = imgIn[i][j];   yp2 = yp1;   yp1 = y;
        }
    }

    /* -------- 4. First vertical accumulation --------------------------- */
    #pragma omp parallel for
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            imgOut[i][j] = c * (y1[i][j] + y2[i][j]);
        }
    }

    /* -------- 5. Forward pass – columns -------------------------------- */
    #pragma omp parallel for
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            const float x = imgOut[i][j];
            const float y = a5 * x + a6 * tm1 + b1 * ym1 + b2 * ym2;
            y1[i][j] = y;
            tm1 = x;   ym2 = ym1;   ym1 = y;
        }
    }

    /* -------- 6. Backward pass – columns --------------------------------*/
    #pragma omp parallel for
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int i = w - 1; i >= 0; --i) {
            const float y = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            y2[i][j] = y;
            tp2 = tp1;   tp1 = imgOut[i][j];   yp2 = yp1;   yp1 = y;
        }
    }

    /* -------- 7. Final accumulation ------------------------------------- */
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            imgOut[i][j] = c * (y1[i][j] + y2[i][j]);
}
