#include <vector>
#include <cstddef>
#include <omp.h>

/* Working with flat, row‑major arrays instead of nested std::vector’s.
   The public signature is kept the same so that the harness continues
   to compile unchanged.  Inside the function we reinterpret the
   flat storage as a 1‑D buffer of size n*n.  This removes the safety
   checks of std::vector and gives the compiler more opportunity for
   vectorisation and better cache usage.                                      */

/* Convert a 2‑D C++ vector into a flat row‑major buffer. */
inline std::vector<double>& flat(std::vector<std::vector<double>>& v)
{
    // Assume all inner vectors are of the same size n.
    std::size_t n = v.size();
    v[0].resize(n*n);                      // allocate a contiguous block
    for (std::size_t i = 1; i < n; ++i)
        v[i].resize(1);                    // dummy to keep 2‑D interface
    return v[0];
}

/* Get element at (row, col) from the flat buffer. */
inline double& elem(std::vector<double>& buf, std::size_t n,
                    std::size_t row, std::size_t col)
{
    return buf[row * n + col];
}

/* Main computational kernel, unchanged external interface. */
void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q)
{
    /* Flatten the 2‑D data structures. */
    std::vector<double>& fu = flat(u);
    std::vector<double>& fv = flat(v);
    std::vector<double>& fp = flat(p);
    std::vector<double>& fq = flat(q);

    /* Pre‑compute constants. */
    const double DX = 1.0 / n;
    const double DY = 1.0 / n;
    const double DT = 1.0 / tsteps;
    const double B1 = 2.0;
    const double B2 = 1.0;
    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);
    const double a = -mul1 / 2.0;
    const double b = 1.0 + mul1;
    const double c = a;
    const double d = -mul2 / 2.0;
    const double e = 1.0 + mul2;
    const double f = d;

    /* Main time looping.  The outer two loops over i and j are
       independent for a fixed time step, so we parallelise over i. */
    for (int t = 1; t <= tsteps; ++t)
    {
        /* First part of the ADI sweep (vertical lines). */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i)
        {
            /* Set boundary values. */
            elem(fv, n, 0, i) = 1.0;
            elem(fp, n, i, 0) = 0.0;
            elem(fq, n, i, 0) = elem(fv, n, 0, i);

            /* Forward sweep over j. */
            for (int j = 1; j < n - 1; ++j)
            {
                double denom1 = a * elem(fp, n, i, j-1) + b;
                elem(fp, n, i, j) = -c / denom1;

                double denom2 = a * elem(fp, n, i, j-1) + b;
                elem(fq, n, i, j) =
                    (-d * elem(fu, n, j, i - 1) + (1.0 + 2.0 * d) * elem(fu, n, j, i)
                     - f * elem(fu, n, j, i + 1) - a * elem(fq, n, i, j - 1)) / denom2;
            }

            elem(fv, n, n - 1, i) = 1.0;

            /* Backward sweep over j. */
            for (int j = n - 2; j >= 1; --j)
            {
                elem(fv, n, j, i) =
                    elem(fp, n, i, j) * elem(fv, n, j + 1, i) + elem(fq, n, i, j);
            }
        }

        /* Second part of the ADI sweep (horizontal lines). */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i)
        {
            elem(fu, n, i, 0) = 1.0;
            elem(fp, n, i, 0) = 0.0;
            elem(fq, n, i, 0) = elem(fu, n, i, 0);

            for (int j = 1; j < n - 1; ++j)
            {
                double denom1 = d * elem(fp, n, i, j-1) + e;
                elem(fp, n, i, j) = -f / denom1;

                double denom2 = d * elem(fp, n, i, j-1) + e;
                elem(fq, n, i, j) =
                    (-a * elem(fv, n, i-1, j) + (1.0 + 2.0 * a) * elem(fv, n, i, j)
                     - c * elem(fv, n, i + 1, j) - d * elem(fq, n, i, j - 1)) / denom2;
            }

            elem(fu, n, i, n - 1) = 1.0;

            for (int j = n - 2; j >= 1; --j)
            {
                elem(fu, n, i, j) =
                    elem(fp, n, i, j) * elem(fu, n, i, j + 1) + elem(fq, n, i, j);
            }
        }
    }
}
